import{_ as e,o as a,c as s,a2 as o}from"./chunks/framework.C69UpXSI.js";const m=JSON.parse('{"title":"Commands","description":"","frontmatter":{},"headers":[],"relativePath":"en/usage/commands.md","filePath":"en/usage/commands.md"}'),d={name:"en/usage/commands.md"};function i(n,t,c,r,l,h){return a(),s("div",null,[...t[0]||(t[0]=[o('<h1 id="commands" tabindex="-1">Commands <a class="header-anchor" href="#commands" aria-label="Permalink to &quot;Commands&quot;">​</a></h1><p>TurboDev slash commands.</p><p>All commands start with <code>/</code>. Type <code>/</code> in the input bar to open the command palette — navigate with <code>↑</code>/<code>↓</code> and select with <code>Enter</code>.</p><h2 id="general-commands" tabindex="-1">General Commands <a class="header-anchor" href="#general-commands" aria-label="Permalink to &quot;General Commands&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Description</th></tr></thead><tbody><tr><td><code>/help</code></td><td>Show available commands</td></tr><tr><td><code>/init</code></td><td>Create or update <code>AGENTS.md</code></td></tr><tr><td><code>/model</code></td><td>Open model selector</td></tr><tr><td><code>/agent</code></td><td>Open agent selector</td></tr><tr><td><code>/setup</code></td><td>Re-run setup wizard</td></tr><tr><td><code>/clear</code></td><td>Clear chat history</td></tr><tr><td><code>/compact</code></td><td>Compact the conversation to free context window</td></tr><tr><td><code>/new</code></td><td>Start a new session</td></tr><tr><td><code>/sessions</code></td><td>List and switch between sessions</td></tr><tr><td><code>/exit</code></td><td>Exit TurboDev</td></tr></tbody></table><h2 id="git-commands" tabindex="-1">Git Commands <a class="header-anchor" href="#git-commands" aria-label="Permalink to &quot;Git Commands&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Description</th></tr></thead><tbody><tr><td><code>/git status</code></td><td>Show working tree status</td></tr><tr><td><code>/git log</code></td><td>Show commit log (default 10 entries)</td></tr><tr><td><code>/git diff</code></td><td>Show unstaged changes</td></tr><tr><td><code>/git add</code></td><td>Stage files (default: all)</td></tr><tr><td><code>/git stash</code></td><td>Stash changes</td></tr><tr><td><code>/git remote</code></td><td>List remotes</td></tr><tr><td><code>/commit &lt;msg&gt;</code></td><td>Stage all files and commit with message</td></tr><tr><td><code>/push</code></td><td>Push current branch to remote</td></tr><tr><td><code>/pull</code></td><td>Pull from remote</td></tr><tr><td><code>/branch</code></td><td>List local branches</td></tr><tr><td><code>/branch &lt;name&gt;</code></td><td>Switch to branch</td></tr><tr><td><code>/rollback</code></td><td>Show recent commits for rollback</td></tr></tbody></table><h2 id="github-commands" tabindex="-1">GitHub Commands <a class="header-anchor" href="#github-commands" aria-label="Permalink to &quot;GitHub Commands&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Description</th></tr></thead><tbody><tr><td><code>/pr list</code></td><td>List open pull requests</td></tr><tr><td><code>/pr &lt;title&gt;</code></td><td>Create a pull request with title</td></tr><tr><td><code>/gh auth</code></td><td>Launch GitHub authentication wizard</td></tr></tbody></table><h2 id="command-details" tabindex="-1">Command Details <a class="header-anchor" href="#command-details" aria-label="Permalink to &quot;Command Details&quot;">​</a></h2><h3 id="init" tabindex="-1">/init <a class="header-anchor" href="#init" aria-label="Permalink to &quot;/init&quot;">​</a></h3><p>Creates or updates <code>AGENTS.md</code> in your project.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/init</span></span></code></pre></div><p>If <code>AGENTS.md</code> already exists, you can choose to:</p><ol><li><strong>Overwrite</strong> — Start fresh</li><li><strong>Append</strong> — Add new sections to existing file</li></ol><p>The wizard detects your project type and generates relevant sections.</p><h3 id="model" tabindex="-1">/model <a class="header-anchor" href="#model" aria-label="Permalink to &quot;/model&quot;">​</a></h3><p>Opens an interactive model selector.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/model</span></span></code></pre></div><p>Navigate with <code>↑</code>/<code>↓</code> or <code>j</code>/<code>k</code>, select with a number (1–9), cancel with <code>Esc</code> or <code>q</code>. If there are more than 9 models, pages are available.</p><h3 id="agent" tabindex="-1">/agent <a class="header-anchor" href="#agent" aria-label="Permalink to &quot;/agent&quot;">​</a></h3><p>Opens the agent selector.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/agent</span></span></code></pre></div><p>Type the agent&#39;s number to select it, press <code>Esc</code> to cancel. Shows all available primary agents with their descriptions.</p><h3 id="setup" tabindex="-1">/setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;/setup&quot;">​</a></h3><p>Re-runs the initial setup wizard to change your API key or model.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/setup</span></span></code></pre></div><h3 id="clear" tabindex="-1">/clear <a class="header-anchor" href="#clear" aria-label="Permalink to &quot;/clear&quot;">​</a></h3><p>Clears the entire chat history and conversation context.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/clear</span></span></code></pre></div><h3 id="compact" tabindex="-1">/compact <a class="header-anchor" href="#compact" aria-label="Permalink to &quot;/compact&quot;">​</a></h3><p>Compacts the conversation by summarizing it via AI. This frees up space in the context window, allowing longer sessions without losing the conversation&#39;s key points.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/compact</span></span></code></pre></div><p>Auto-compaction triggers at <strong>85%</strong> of the context window. You&#39;ll be notified at <strong>75%</strong>. Use <code>/compact</code> manually at any time.</p><h3 id="new" tabindex="-1">/new <a class="header-anchor" href="#new" aria-label="Permalink to &quot;/new&quot;">​</a></h3><p>Starts a new empty session. The current session is saved automatically and can be resumed later with <code>/sessions</code>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/new</span></span></code></pre></div><h3 id="sessions" tabindex="-1">/sessions <a class="header-anchor" href="#sessions" aria-label="Permalink to &quot;/sessions&quot;">​</a></h3><p>Lists all saved sessions sorted by most recent. Select a session by number to restore it.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/sessions</span></span></code></pre></div><p>Shows each session with its title, relative time, and message count. Press <code>Esc</code> to cancel.</p><h3 id="commit" tabindex="-1">/commit <a class="header-anchor" href="#commit" aria-label="Permalink to &quot;/commit&quot;">​</a></h3><p>Stages all changes and commits with the provided message.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/commit fix: resolve login issue</span></span></code></pre></div><p>Equivalent to <code>git add -A &amp;&amp; git commit -m &quot;fix: resolve login issue&quot;</code>.</p><h3 id="gh-auth" tabindex="-1">/gh auth <a class="header-anchor" href="#gh-auth" aria-label="Permalink to &quot;/gh auth&quot;">​</a></h3><p>Launches the GitHub authentication wizard. Supports browser-based login or personal access token. Requires the <a href="https://cli.github.com/" target="_blank" rel="noreferrer">GitHub CLI (<code>gh</code>)</a> to be installed.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gh auth</span></span></code></pre></div><h3 id="exit" tabindex="-1">/exit <a class="header-anchor" href="#exit" aria-label="Permalink to &quot;/exit&quot;">​</a></h3><p>Exits TurboDev.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/exit</span></span></code></pre></div>',51)])])}const u=e(d,[["render",i]]);export{m as __pageData,u as default};
